import React from 'react';
import TabelaRelatorioEconomico from '../components/TabelaRelatorioEconomico';

const anoAtual = new Date().getFullYear();
const dataLinhas = [
  `30/09/${anoAtual}`,
  `30/09/${anoAtual}`,
  `30/09/${anoAtual}`,
  `31/12/${anoAtual}`,
  `31/12/${anoAtual}`,
  `31/12/${anoAtual}`,
];

export default function RelatorioSegundoSemestre() {
  let razaoSocial = '';
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      if (obj.razaoSocial) razaoSocial = obj.razaoSocial;
    }
  } catch {}
  return <TabelaRelatorioEconomico datasPadrao={dataLinhas} razaoSocial={razaoSocial} semestre="SEM2" ano={anoAtual} />;
}
